#include <stdio.h> // Required for scanf and printf

int main() {
    int N; // Variable to store the number of items
    double item_price; // Variable to store the price of a single item
    double item_quantity; // Variable to store the quantity of a single item
    double total_cost = 0.0; // Variable to accumulate the total cost of all items, initialized to 0
    double final_cost; // Variable to store the cost after any potential discount

    // Read the number of distinct items from stdin
    scanf("%d", &N);

    // Loop N times to read details for each item and update total_cost
    for (int i = 0; i < N; i++) {
        // Read item price and quantity for the current item
        scanf("%lf %lf", &item_price, &item_quantity);
        // Calculate the cost for this item and add it to total_cost
        // Uses multiplication operator (*) and addition assignment operator (+=)
        total_cost += (item_price * item_quantity);
    }

    // Check if the total_cost exceeds $100.00 to apply a discount
    // Uses relational operator (>) for comparison
    if (total_cost > 100.00) {
        // If total_cost is greater than 100, apply a 10% discount
        // Uses multiplication operator (*)
        final_cost = total_cost * 0.90; // 0.90 represents 100% - 10% = 90% of the original cost
    } else {
        // If total_cost is not greater than 100, no discount is applied
        final_cost = total_cost;
    }

    // Print the final calculated cost, formatted to two decimal places, followed by a newline
    printf("%.2lf\n", final_cost);

    return 0; // Indicate successful program execution
}
